{
  "summary": "This paper formulates Continual Knowledge Learning (CKL) as a novel problem focused on continually updating the internal knowledge of language models through continued pretraining on new corpora. It introduces a benchmark with datasets probing invariant, updated, and new knowledge, proposes the FUAR metric to measure forgetting versus acquisition, and evaluates various baseline methods, highlighting parameter-expansion approaches as most effective but memory-inefficient.",
  "strengths": [
    {
      "point": "Novel problem formulation addressing continual updating of LM knowledge",
      "evidence": "The paper clearly defines CKL as a new continual learning problem distinct from targeted knowledge editing or traditional CL, focusing on scalable continual pretraining to renew world knowledge."
    },
    {
      "point": "Comprehensive benchmark and metric for evaluating knowledge retention and update",
      "evidence": "The authors construct datasets (INVARIANT, UPDATED, NEW LAMA) derived from LAMA to probe different knowledge types and propose the FUAR metric to quantify the trade-off between forgetting and learning."
    },
    {
      "point": "Extensive experimental evaluation of multiple baseline methods",
      "evidence": "The paper adapts regularization, rehearsal, and parameter-expansion methods, providing detailed results on T5-large and GPT-2, including multiple CKL phases, learning rates, and transfer to downstream tasks."
    },
    {
      "point": "Insightful analysis of challenges such as forgetting, memory inefficiency, and learning rate trade-offs",
      "evidence": "The study reveals that parameter-expansion methods best balance forgetting and acquisition but suffer from memory inefficiency, and that repeated exposure to small corpora increases forgetting."
    },
    {
      "point": "Commitment to resource release to facilitate future research",
      "evidence": "The authors plan to publicly release benchmark datasets, evaluation scripts, and baseline code."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient positioning relative to targeted knowledge editing methods",
      "evidence": "The paper does not adequately compare CKL to recent editing methods like ROME and MEMIT or discuss potential synergies or distinctions."
    },
    {
      "point": "Limited justification and analysis of the large corpus size discrepancy between original and update corpora",
      "evidence": "The smaller \(D_1\) corpus is about 750 times smaller than \(D_0\), but the paper lacks a systematic study on corpus size scaling, domain shift effects, or practical implications."
    },
    {
      "point": "Missing fine-grained ablation on different knowledge types within benchmark datasets",
      "evidence": "The paper does not analyze how various knowledge categories (factual, commonsense, temporal) affect forgetting or acquisition, nor details annotation protocols."
    },
    {
      "point": "Baseline evaluations omit recent state-of-the-art parameter-efficient and dynamic routing methods",
      "evidence": "Methods like prefix-tuning or adapters with dynamic routing are not included or discussed, limiting the comprehensiveness of the evaluation."
    },
    {
      "point": "Sparse details on Mix-Review baseline implementation and hyperparameters",
      "evidence": "Critical hyperparameters such as mixing ratios and sampling strategies are not reported, undermining reproducibility and fairness."
    },
    {
      "point": "FUAR metric oversimplifies the complex trade-off without complementary metrics",
      "evidence": "The paper does not discuss FUAR limitations or complement it with precision, recall, or consistency measures to capture nuanced knowledge retention."
    },
    {
      "point": "Insufficient reporting of continued pretraining hyperparameters and training details",
      "evidence": "Key details like batch size, optimizer settings, learning rate schedules, and early stopping are missing, hindering exact replication."
    },
    {
      "point": "Limited description of dataset construction, annotation protocols, and quality control",
      "evidence": "The paper lacks detailed annotation guidelines, inter-annotator agreement statistics, and quality assurance measures for benchmark datasets."
    },
    {
      "point": "Ambiguity in definition and operationalization of 'time-invariant' knowledge",
      "evidence": "Criteria for selecting invariant facts are unclear, complicating interpretation of forgetting results."
    },
    {
      "point": "Memory inefficiency of parameter-expansion methods not addressed with mitigation strategies",
      "evidence": "No exploration of pruning, distillation, or parameter sharing to reduce memory overhead despite acknowledging the issue."
    },
    {
      "point": "Multiple CKL phases lead to degraded performance without proposed solutions",
      "evidence": "The paper shows performance degradation over multiple update phases but does not suggest or test mitigation techniques."
    },
    {
      "point": "Generalisability limited by evaluation on only T5-large and GPT-2",
      "evidence": "No experiments on larger or more diverse architectures like GPT-3 or PaLM to assess scalability."
    },
    {
      "point": "Downstream evaluation restricted to KILT benchmark",
      "evidence": "No assessment on other knowledge-intensive tasks such as open-domain QA or fact verification beyond KILT."
    },
    {
      "point": "Presentation of results could be enhanced with more intuitive visualizations and qualitative examples",
      "evidence": "The paper relies heavily on tables and numeric metrics without forgetting curves, heatmaps, or case studies."
    },
    {
      "point": "No exploration of alternative training objectives beyond continued pretraining",
      "evidence": "Methods like contrastive learning, knowledge distillation, or retrieval-augmented approaches are not investigated."
    },
    {
      "point": "No discussion of computational cost and efficiency of CKL methods",
      "evidence": "Resource requirements and training time are not analyzed, limiting practical feasibility assessment."
    },
    {
      "point": "Absence of qualitative analysis or case studies of knowledge updates",
      "evidence": "Lack of examples illustrating successes or failures in knowledge updating reduces interpretability."
    },
    {
      "point": "No consideration of potential negative transfer or conflicting knowledge updates",
      "evidence": "The paper does not address how contradictory new information is handled or its impact on model consistency."
    },
    {
      "point": "Limited analysis of domain shift between \(D_0\) and \(D_1\) and its impact",
      "evidence": "Domain differences between general web corpora and news articles are not explicitly studied."
    },
    {
      "point": "No examination of the effect of model size or capacity on CKL outcomes",
      "evidence": "The influence of model scale on forgetting, acquisition, or efficiency is not investigated."
    }
  ],
  "questions": [
    {
      "question": "How does CKL fundamentally differ from targeted knowledge editing methods, and can these approaches be combined?",
      "motivation": "Clarifying this would position CKL within the broader knowledge updating landscape and identify potential synergies."
    },
    {
      "question": "What is the impact of domain shift and corpus size scaling on CKL performance and forgetting?",
      "motivation": "Understanding this is critical for applying CKL in realistic scenarios with varying data availability and domain differences."
    },
    {
      "question": "Can parameter-expansion methods be made more memory efficient through pruning, distillation, or parameter sharing?",
      "motivation": "Addressing memory inefficiency is essential for practical deployment in long-term continual learning."
    },
    {
      "question": "How do different knowledge categories (factual, commonsense, temporal) affect forgetting and acquisition in CKL?",
      "motivation": "Fine-grained analysis would guide method improvements and benchmark design."
    },
    {
      "question": "How do CKL methods handle conflicting or contradictory new information in the update corpus?",
      "motivation": "Real-world data often contains inconsistencies; robustness to such conflicts is vital for reliable knowledge updating."
    },
    {
      "question": "What are the computational costs and resource requirements of CKL methods, especially parameter-expansion approaches?",
      "motivation": "Resource efficiency impacts feasibility and scalability in practical applications."
    },
    {
      "question": "How does model size or architecture influence CKL effectiveness and forgetting?",
      "motivation": "Insights here would inform applicability across diverse LM scales and designs."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
